def classify_email(email_text: str) -> str:
    response = client.messages.create(
        model='claude-haiku-4-5-20260101',
        max_tokens=20,  # just a label, no need for more
        messages=[{'role': 'user', 'content': f'''
Classify this email as one word: urgent/normal/spam/inquiry
Email: {email_text[:500]}
'''}]
    )
    return response.content[0].text.strip().lower()
# ~200 tokens per call = $0.000016/email
# 100,000 emails/day = $1.60/day

def analyze_long_doc(doc_text: str, question: str) -> str:
    # Repeat question at top AND bottom — key technique
    prompt = f'''
Question: {question}
<document>
{doc_text}
</document>
Now answer the question above: {question}
Cite which section your answer comes from.
'''
    return client.messages.create(
        model='claude-sonnet-4-6-20260101',
        max_tokens=2000,
        messages=[{'role': 'user', 'content': prompt}]
    ).content[0].text

import time, random, anthropic

def call_with_retry(messages, max_retries=5):
    for attempt in range(max_retries):
        try:
            return client.messages.create(
                model='claude-sonnet-4-6-20260101',
                max_tokens=1024,
                messages=messages
            )
        except anthropic.RateLimitError:
            if attempt == max_retries - 1: raise
            wait = (2 ** attempt) + random.uniform(0, 1)
            print(f'Rate limit hit. Waiting {wait:.1f}s...')
            time.sleep(wait)
